function playerValuation(p){if(!p)return{total:0,breakdown:[]};const base=overallBase(p.overall),age=Math.round(base*(ageFactor(p)-1)),devRate=({'Normal':0,'Star':.08,'Superstar':.18,'X-Factor':.28}[p.dev]||0)*(p.age<=24?1.16:p.age>=31?.76:1),dev=Math.round(base*devRate),pos=Math.round(base*((POS_MULT[POS_GROUP[p.position]]||1)-1)),market=Math.max(1,(p.overall-68)*.62),capEfficiency=(market-(p.capHit||0))/Math.max(5,market),rookie=(p.age<=24&&p.years>=3)?Math.round(base*.13):0,yearsControl=p.years>=4?Math.round(base*.06):p.years===1?-Math.round(base*.07):0,contract=Math.round(base*Math.max(-.24,Math.min(.20,capEfficiency*.15)))+rookie+yearsControl,production=productionScore(p),elite=p.overall>=95?Math.round(base*.13):p.overall>=90?Math.round(base*.06):0,risk=p.injury!=='Healthy'?-Math.round(base*.35):0,total=Math.max(100,base+age+dev+pos+contract+production+elite+risk);return{model:MODEL_VERSION,total,tradeable:p.injury==='Healthy',breakdown:[['Overall rating',base,`${p.overall} OVR curved base`],['Age & window',age,`${p.age} years · dynasty-leaning curve`],['Development',dev,p.dev],['Contract & control',contract,`${p.years} yrs · ${formatMoney(p.capHit)} cap hit`],['Production',production,'Mock current-season production'],['Position scarcity',pos,POS_GROUP[p.position]||p.position],['Elite premium',elite,p.overall>=90?'Premium asset protection':'Not applied'],['Risk',risk,p.injury]]}}
