function generateAISuggestions(){
 const a=me();if(!a.teamId)return[];
 const own=a.teamId,profile=teamPositionProfile(own),needs=profile.sort((x,y)=>x.best-y.best).slice(0,5).map(x=>x.position);
 const ownPlayers=players.filter(p=>p.teamId===own).sort((x,y)=>value(P(x))-value(P(y)));
 const targets=players.filter(p=>p.teamId!==own&&needs.includes(p.position)&&p.overall>=78).sort((x,y)=>{
   const xb=onBlock(x)?1:0,yb=onBlock(y)?1:0;return yb-xb||y.overall-x.overall||x.age-y.age
 }).slice(0,8);
 return targets.map((target,index)=>{
   const targetAsset=P(target),targetValue=value(targetAsset),targetTeam=target.teamId;
   let candidate=ownPlayers.filter(p=>p.position!==target.position&&p.overall>=72&&p.overall<=target.overall+2).sort((x,y)=>Math.abs(value(P(x))-targetValue*.62)-Math.abs(value(P(y))-targetValue*.62))[0]||ownPlayers[Math.min(index,ownPlayers.length-1)];
   const assetsA=candidate?[P(candidate)]:[];let current=total(assetsA);
   if(current<targetValue*.88){const pick=suggestionPick(own,targetValue,current);if(pick&&!assetsA.some(x=>assetKey(x)===assetKey(pick))){assetsA.push(pick);current=total(assetsA)}}
   const assetsB=[targetAsset];const fairness=fair(total(assetsA),total(assetsB));
   const needRank=needs.indexOf(target.position)+1;
   return{id:`ai-${target.id}-${index}`,teamAId:own,teamBId:targetTeam,assetsA,assetsB,target,fairness,reason:`${target.position} grades as your #${needRank} roster need. ${onBlock(target)?`${target.name} is already available on the Trade Block.`:`This package targets a younger or higher-impact option at the position.`}`,confidence:Math.max(68,Math.min(96,Math.round((fairness+target.overall)/2)))}
 }).filter(s=>s.assetsA.length&&s.fairness>=72).slice(0,6)
}
function suggestionAssetLine(a){if(a.type==='player'){const p=playerById(a.id);return`<span>${escapeHtml(p?.position||'')} · <strong>${escapeHtml(p?.name||'Player')}</strong><small>${p?.overall||'—'} OVR</small></span>`}return`<span><strong>${a.year} Round ${a.round}</strong><small>${draftDistance(a.year)===1?'Next draft':`${draftDistance(a.year)} drafts away`}</small></span>`}
