function chat(t,v,a){const target=sameParty(a,v.targetId),msgs=t.chat.map(m=>m.authorId==='system'?`<div class="chat-system"><span>${escapeHtml(m.text)}</span><small>${escapeHtml(m.at)}</small></div>`:(()=>{const au=acc(m.authorId),own=m.authorId===a.id;return`<div class="chat-message ${own?'chat-message--own':''}"><span class="avatar">${au?.initials||'U'}</span><div><span><strong>${escapeHtml(au?.handle||'Owner')}</strong><small>${escapeHtml(m.at)}</small></span><p>${escapeHtml(m.text)}</p></div></div>`})()).join('');return`<div class="negotiation-layout"><article class="private-chat card"><div class="card-header"><div><span class="eyebrow">Private negotiation thread</span><h3>Owner messages</h3></div><span class="pill pill--accent">Only both owners</span></div><div class="chat-messages">${msgs}</div><div class="chat-compose"><textarea data-chat-input placeholder="Message the other owner privately..."></textarea><button class="button button--primary" data-send-chat="${t.id}">Send</button></div></article><aside class="negotiation-actions card"><span class="eyebrow">Current action</span><h3>${target?'Respond to this version':`Waiting on ${escapeHtml(acc(v.targetId)?.handle||'owner')}`}</h3><p>${target?'Accept sends this exact version to the hidden committee. Countering creates a new version.':'Continue chatting or propose another revision.'}</p>${target?`<button class="button button--primary button--full" data-accept="${t.id}">Accept and send to committee</button><button class="button button--secondary button--full" data-revise>Counter offer</button><button class="button button--danger button--full" data-decline="${t.id}">Decline offer</button>`:'<button class="button button--secondary button--full" data-revise>Propose revision</button><button type="button" class="button button--danger button--full" data-withdraw="${escapeHtml(String(t.negotiationId||t.id))}" data-negotiation-id="${escapeHtml(String(t.negotiationId||t.id))}" aria-label="Withdraw and close this negotiation">Withdraw and close negotiation</button>'}<div class="negotiation-note"><svg><use href="#icon-info"></use></svg><span>Private chat and old versions are never shown to committee.</span></div></aside></div>`}
function committeeConflict(t,a=me()){if(!t||!a)return false;const ownedTeam=a.role==='committee'?a.ownerTeamId:a.role==='commissioner'?a.teamId:null;return!!(ownedTeam&&[t.teamAId,t.teamBId].includes(ownedTeam))}
